#!/usr/bin/env bash
# exportcommands.sh — Export ~/.claude/ dirs to jleechanorg/claude-commands
#
# Behavior:
#   - Source files overwrite target files (rsync default)
#   - Files only in target are PRESERVED (rsync default; no --delete flag)
#   - README.md is regenerated by Claude CLI
#   - Content filters strip project-specific strings via perl -pi -e (supports \b on macOS)
#
# Usage: bash ~/.claude/commands/exportcommands.sh [--dry-run]

set -euo pipefail

# ── Config ─────────────────────────────────────────────────────────────────
TARGET_REPO="jleechanorg/claude-commands"
BRANCH="export-$(date +%Y%m%d-%H%M%S)"
REPO_DIR="$(mktemp -d)/claude-commands"

# ── Cleanup trap — remove temp dir on exit (normal or error) ────────────────
trap 'rm -rf "$(dirname "$REPO_DIR")"' EXIT
SOURCE_CLAUDE="$HOME/.claude"
# Detect project root: honour $PROJECT_ROOT env var, then git root of current dir.
# Fail fast if git rev-parse fails — do not silently export to a bogus path.
if [[ -z "${PROJECT_ROOT:-}" ]]; then
  PROJECT_ROOT="$(git rev-parse --show-toplevel 2>/dev/null)" || {
    echo "ERROR: PROJECT_ROOT is unset and git rev-parse failed. Set PROJECT_ROOT before running." >&2
    exit 1
  }
fi

DRY_RUN=false
[[ "${1:-}" == "--dry-run" ]] && DRY_RUN=true

# Dirs from ~/.claude/ → .claude/<dir> in target repo
CLAUDE_DIRS=(commands skills hooks agents scripts)

# Dirs from project root → repo root in target repo
ROOT_DIRS=(orchestration automation ralph)

# Files to exclude from content filtering (contain literal regex patterns or are test files
# that assert on the source strings and must not have them silently replaced)
FILTER_SKIP=(exportcommands.py exportcommands.sh loc_simple.sh test_exportcommands.py)

# Content filter substitutions (applied to all .md .py .sh .yml files)
# NOTE: Uses perl -pi -e for cross-platform \b word-boundary support (macOS sed lacks it)
# IMPORTANT: Specific patterns must come before general ones:
#   jleechanorg/worldarchitect.ai BEFORE worldarchitect.ai (general would consume specific)
declare -a SUBS=(
  's|jleechanorg/worldarchitect\.ai|\$GITHUB_REPOSITORY|g'
  's|worldarchitect\.ai|your-project.com|g'
  's|worldarchitect-ci|\$\{PROJECT_NAME:-your-project\}-ci|g'
  's|/Users/jleechan|\$HOME|g'
  's|\bjleechan\b|\$USER|g'
  's|jleechantest\@gmail\.com|<your-email\@gmail.com>|g'
  's|mvp_site/|\$PROJECT_ROOT/|g'
  's|WorldArchitect\.AI|Your Project|g'
  's|TESTING=true vpython|TESTING=true python|g'
)

# ── Helpers ─────────────────────────────────────────────────────────────────
log()  { echo "  $*"; }
ok()   { echo "  ✅ $*"; }
warn() { echo "  ⚠️  $*" >&2; }

apply_filters() {
  local file="$1"
  local base; base="$(basename "$file")"
  for skip in "${FILTER_SKIP[@]}"; do
    [[ "$base" == "$skip" ]] && return 0
  done
  # Use perl -pi -e: supports \b word boundaries on macOS (BSD sed lacks \b)
  for sub in "${SUBS[@]}"; do
    perl -pi -e "$sub" "$file"
  done
}

# ── Clone & branch ──────────────────────────────────────────────────────────
echo "▶ Cloning $TARGET_REPO..."
gh repo clone "$TARGET_REPO" "$REPO_DIR"
cd "$REPO_DIR"

git config user.email "claude-export@anthropic.com"
git config user.name "Claude Export"
git config commit.gpgsign false

git checkout main
git pull --ff-only origin main
git checkout -b "$BRANCH"

# ── Rsync .claude/ directories ──────────────────────────────────────────────
echo "▶ Syncing .claude/ directories..."
for dir in "${CLAUDE_DIRS[@]}"; do
  src="$SOURCE_CLAUDE/$dir/"
  dst=".claude/$dir/"
  if [[ ! -d "$src" ]]; then
    warn "$dir not found at $src — skipping"
    continue
  fi
  mkdir -p "$dst"
  rsync -a \
    --exclude='*.pyc' \
    --exclude='__pycache__/' \
    --exclude='.DS_Store' \
    --exclude='.ruff_cache/' \
    --exclude='exportcommands.py' \
    "$src" "$dst"
  ok "$dir"
done

# ── Rsync root-level directories ─────────────────────────────────────────────
echo "▶ Syncing root directories..."
for dir in "${ROOT_DIRS[@]}"; do
  src="$PROJECT_ROOT/$dir/"
  dst="./$dir/"
  if [[ ! -d "$src" ]]; then
    warn "$dir not found at $src — skipping"
    continue
  fi
  mkdir -p "$dst"
  rsync -a \
    --exclude='*.pyc' \
    --exclude='__pycache__/' \
    --exclude='.DS_Store' \
    "$src" "$dst"
  ok "$dir"
done


# ── Remove files that must not be in the public template ─────────────────────
# settings.json / settings.local.json: MCP auth tokens + bypassPermissions flags (never publish)
rm -f ".claude/settings.json"
rm -f ".claude/settings.local.json"
# exportcommands.py: deprecated 2347-line Python script, contains hardcoded paths
# that cannot be filtered (it's in FILTER_SKIP to protect its regex patterns)
rm -f ".claude/commands/exportcommands.py"

# ── Copy GitHub workflows (examples only) ───────────────────────────────────
if [[ -d "$PROJECT_ROOT/.github/workflows" ]]; then
  mkdir -p "workflows"
  rsync -a \
    --include='*.yml' --include='*.yaml' --exclude='*' \
    "$PROJECT_ROOT/.github/workflows/" "workflows/"
  ok "workflows (examples)"
fi

# ── Apply content filters ────────────────────────────────────────────────────
echo "▶ Applying content filters..."
while IFS= read -r -d '' file; do
  apply_filters "$file"
done < <(find .claude orchestration automation ralph workflows \
  -type f \( -name '*.md' -o -name '*.py' -o -name '*.sh' -o -name '*.yml' -o -name '*.yaml' \) \
  -print0 2>/dev/null)
ok "Filters applied"

# ── Hardcoded path scan ──────────────────────────────────────────────────────
echo "▶ Scanning for leaked paths..."
LEAKED=$(grep -rl \
  --include='*.md' --include='*.py' --include='*.sh' --include='*.yml' --include='*.yaml' \
  -e '/Users/jleechan' -e 'jleechantest@gmail' \
  .claude orchestration automation ralph workflows 2>/dev/null \
  | grep -v exportcommands || true)
if [[ -n "$LEAKED" ]]; then
  warn "Hardcoded paths found — check filter list:"
  echo "$LEAKED" | sed 's/^/     /'
fi

# ── Update README via Claude CLI (preserve existing, update changelog only) ──
echo "▶ Updating README.md via Claude..."

# Capture diff stat BEFORE git add so we know what changed vs previous state
DIFF_STAT=$(git diff --stat 2>/dev/null || true)
NEW_FILES=$(git status --short 2>/dev/null | grep '^?' | awk '{print $2}' | head -20 || true)

if command -v claude >/dev/null 2>&1 && [[ -f "README.md" ]]; then
  EXISTING_README=$(cat README.md)
  COMMANDS_COUNT=$(find .claude/commands -name '*.md' 2>/dev/null | wc -l | tr -d ' ')
  SKILLS_COUNT=$(find .claude/skills -name '*.md' 2>/dev/null | wc -l | tr -d ' ')

  README_PROMPT="You are updating the README for the jleechanorg/claude-commands GitHub repository.

Here is the EXISTING README (preserve all text except what needs updating):
---
${EXISTING_README}
---

Here is what changed in this export (git diff --stat):
${DIFF_STAT:-No file changes detected}

New files added this export:
${NEW_FILES:-None}

Current counts: ${COMMANDS_COUNT} commands, ${SKILLS_COUNT} skill files.

TASK — make MINIMAL updates only:
1. Add or update a ## Changelog section near the top with today's date ($(date +%Y-%m-%d)) listing new/changed files briefly
2. If new slash commands appear in the diff that are not already mentioned in the README, add a one-line entry for each in the relevant section
3. Update any command/file counts if they changed significantly
4. Preserve ALL other text EXACTLY as-is — do not rewrite, reformat, or rephrase anything else

Output ONLY the updated markdown. No preamble, no explanation, no code fences."

  # Write prompt to temp file to avoid shell quoting issues with large README content
  PROMPT_FILE=$(mktemp /tmp/exportcommands_prompt.XXXXXX)
  printf '%s' "$README_PROMPT" > "$PROMPT_FILE"
  # Always generate README.md.new for preview; only overwrite README.md in non-dry-run
  claude -p "$(cat "$PROMPT_FILE")" > README.md.new 2>/dev/null \
    || { rm -f README.md.new; warn "Claude CLI failed — keeping existing README unchanged"; }
  rm -f "$PROMPT_FILE"
  if [[ -f "README.md.new" ]]; then
    if [[ "$DRY_RUN" == "false" ]]; then
      mv README.md.new README.md
      ok "README.md updated (changelog + new commands only)"
    else
      ok "README.md.new generated for preview (dry-run — not overwriting README.md)"
    fi
  fi

elif command -v claude >/dev/null 2>&1 && [[ ! -f "README.md" ]]; then
  # No existing README — generate fresh one (first-time export)
  COMMANDS_COUNT=$(find .claude/commands -name '*.md' 2>/dev/null | wc -l | tr -d ' ')
  SKILLS_COUNT=$(find .claude/skills -name '*.md' 2>/dev/null | wc -l | tr -d ' ')
  HOOKS_COUNT=$(find .claude/hooks \( -name '*.sh' -o -name '*.py' \) 2>/dev/null | wc -l | tr -d ' ')

  README_PROMPT="Generate a concise README.md for the jleechanorg/claude-commands GitHub repository.
- 1-sentence description: reference export of a Claude Code CLI configuration
- Contains: ${COMMANDS_COUNT} slash commands, ${SKILLS_COUNT} skill files, ${HOOKS_COUNT} hooks
- Quick Start: copy .claude/ dirs or run bash ~/.claude/commands/exportcommands.sh
- Directory overview: .claude/commands/, .claude/skills/, .claude/hooks/, .claude/agents/, .claude/scripts/
- List 6-8 useful commands: /pr, /copilot, /tdd, /harness, /exportcommands, /fixpr, /orch, /converge
- Include ## Changelog section with entry for $(date +%Y-%m-%d): initial export
- Under 120 lines, GitHub-flavored markdown
- Output ONLY the markdown, no preamble"

  if [[ "$DRY_RUN" == "false" ]]; then
    claude -p "$README_PROMPT" > README.md 2>/dev/null && ok "README.md created (first export)" \
      || warn "Claude CLI failed — no README generated"
  else
    claude -p "$README_PROMPT" > README.md.new 2>/dev/null && ok "README.md.new generated for preview (dry-run)" \
      || warn "Claude CLI failed — no README preview generated"
  fi
else
  warn "Skipping README update (claude CLI not found)"
fi

# ── Commit & push ────────────────────────────────────────────────────────────
git add -A

if git diff --cached --quiet; then
  echo "No changes detected — nothing to export."
  exit 0
fi

CHANGED=$(git diff --cached --stat | tail -1)
git commit -m "export: $(date +%Y-%m-%d) — $CHANGED"

if [[ "$DRY_RUN" == "true" ]]; then
  echo "DRY RUN — skipping push and PR creation."
  echo "Branch: $BRANCH | Repo: $REPO_DIR"
  exit 0
fi

git push -u origin "$BRANCH"

PR_STDERR=$(mktemp /tmp/exportcommands_pr_err.XXXXXX)
PR_URL=$(gh api repos/"$TARGET_REPO"/pulls --method POST \
  -f title="Claude Commands Export $(date +%Y-%m-%d)" \
  -f head="$BRANCH" \
  -f base="main" \
  -f body="Automated export. Source files overwrite target; target-only files preserved.

Changed: $CHANGED" \
  --jq '.html_url' 2>"$PR_STDERR") || {
    warn "PR creation failed: $(cat "$PR_STDERR")"
    rm -f "$PR_STDERR"
    exit 1
  }
rm -f "$PR_STDERR"

echo ""
echo "✅ Export complete!"
echo "   PR: $PR_URL"
echo "   Branch: $BRANCH"
